222→
223→        let proto = envelope.to_protocol().expect("convert to protocol");
224→        assert_eq!(proto.seq, 42);
225→        assert_eq!(proto.event_id.as_str(), "EVT001");
226→        assert!(matches!(
227→            proto.kind,
