420→impl Journal for RedbJournal {
421→    fn append(
422→        &self,
423→        event: EventEnvelope,
424→    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<SeqNo>> + Send + '_>> {
425→        let db = Arc::clone(&self.db);
426→        let notify_tx = self.notify_tx.clone();
427→        Box::pin(async move {
428→            let events = vec![event];
429→            let (last_seq, notifications) =
430→                tokio::task::spawn_blocking(move || Self::append_batch_blocking(&db, events))
431→                    .await
432→                    .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))??;
433→
434→            for notification in notifications {
435→                let _ = notify_tx.send(notification);
436→            }
437→            debug!(seq = last_seq, "appended event");
438→            Ok(last_seq)
439→        })
440→    }
441→
442→    fn append_batch(
443→        &self,
444→        events: Vec<EventEnvelope>,
445→    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<SeqNo>> + Send + '_>> {
446→        let db = Arc::clone(&self.db);
447→        let notify_tx = self.notify_tx.clone();
448→        Box::pin(async move {
449→            if events.is_empty() {
450→                return Ok(0);
451→            }
452→            let (last_seq, notifications) =
453→                tokio::task::spawn_blocking(move || Self::append_batch_blocking(&db, events))
454→                    .await
455→                    .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))??;
456→
457→            for notification in notifications {
458→                let _ = notify_tx.send(notification);
459→            }
460→            debug!(seq = last_seq, "appended batch");
461→            Ok(last_seq)
462→        })
463→    }
464→
465→    fn read(
466→        &self,
467→        query: EventQuery,
468→    ) -> std::pin::Pin<
469→        Box<dyn std::future::Future<Output = LagoResult<Vec<EventEnvelope>>> + Send + '_>,
470→    > {
471→        let db = Arc::clone(&self.db);
472→        Box::pin(async move {
473→            tokio::task::spawn_blocking(move || Self::read_blocking(&db, query))
474→                .await
475→                .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
476→        })
477→    }
478→
479→    fn get_event(
480→        &self,
481→        event_id: &EventId,
482→    ) -> std::pin::Pin<
483→        Box<dyn std::future::Future<Output = LagoResult<Option<EventEnvelope>>> + Send + '_>,
484→    > {
485→        let id_str = event_id.as_str().to_string();
486→        let db = Arc::clone(&self.db);
487→        Box::pin(async move {
488→            tokio::task::spawn_blocking(move || Self::get_event_blocking(&db, &id_str))
489→                .await
490→                .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
491→        })
492→    }
493→
494→    fn head_seq(
495→        &self,
496→        session_id: &SessionId,
497→        branch_id: &BranchId,
498→    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<SeqNo>> + Send + '_>> {
499→        let db = Arc::clone(&self.db);
500→        let sid = session_id.as_str().to_string();
501→        let bid = branch_id.as_str().to_string();
502→        Box::pin(async move {
503→            tokio::task::spawn_blocking(move || Self::head_seq_blocking(&db, &sid, &bid))
504→                .await
505→                .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
506→        })
507→    }
508→
509→    fn stream(
510→        &self,
511→        session_id: SessionId,
512→        branch_id: BranchId,
513→        after_seq: SeqNo,
514→    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<EventStream>> + Send + '_>>
515→    {
516→        let db = Arc::clone(&self.db);
517→        let rx = self.notify_tx.subscribe();
518→        Box::pin(async move {
519→            let tail = EventTailStream::new(db, rx, session_id, branch_id, after_seq);
520→            Ok(Box::pin(tail) as EventStream)
521→        })
522→    }
523→
524→    fn put_session(
525→        &self,
526→        session: Session,
527→    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<()>> + Send + '_>> {
528→        let db = Arc::clone(&self.db);
529→        Box::pin(async move {
530→            tokio::task::spawn_blocking(move || Self::put_session_blocking(&db, session))
531→                .await
532→                .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
533→        })
534→    }
535→
536→    fn get_session(
537→        &self,
538→        session_id: &SessionId,
539→    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<Option<Session>>> + Send + '_>>
540→    {
541→        let db = Arc::clone(&self.db);
542→        let sid = session_id.as_str().to_string();
543→        Box::pin(async move {
544→            tokio::task::spawn_blocking(move || Self::get_session_blocking(&db, &sid))
545→                .await
546→                .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
547→        })
548→    }
549→
550→    fn list_sessions(
551→        &self,
552→    ) -> std::pin::Pin<Box<dyn std::future::Future<Output = LagoResult<Vec<Session>>> + Send + '_>>
553→    {
554→        let db = Arc::clone(&self.db);
555→        Box::pin(async move {
556→            tokio::task::spawn_blocking(move || Self::list_sessions_blocking(&db))
557→                .await
558→                .map_err(|e| LagoError::Journal(format!("spawn_blocking join error: {e}")))?
559→        })
560→    }
561→}
