//! Golden fixture replay tests for the Lago journal.
//!
//! These tests load deterministic JSON fixture files from `conformance/fixtures/`,
//! append them to a fresh RedbJournal, and verify that events survive the full
//! serialization/storage/deserialization pipeline with correct payloads, sequence
//! assignment, and branch isolation.

use lago_core::event::{EventEnvelope, EventPayload};
use lago_core::id::{BranchId, SessionId};
use lago_core::{EventQuery, Journal};
use lago_journal::RedbJournal;
use tempfile::TempDir;

const FIXTURES_DIR: &str = concat!(env!("CARGO_MANIFEST_DIR"), "/../../../conformance/fixtures");

fn load_fixture(name: &str) -> Vec<EventEnvelope> {
    let path = format!("{FIXTURES_DIR}/{name}");
    let data = std::fs::read_to_string(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));
    serde_json::from_str(&data).unwrap_or_else(|e| panic!("parse {path}: {e}"))
}

fn setup() -> (TempDir, RedbJournal) {
    let dir = TempDir::new().unwrap();
    let journal = RedbJournal::open(&dir.path().join("golden.redb")).unwrap();
    (dir, journal)
}

async fn ingest(journal: &RedbJournal, fixtures: &[EventEnvelope]) {
    for event in fixtures {
        journal.append(event.clone()).await.unwrap();
    }
}

// ─── simple-chat fixtures ───────────────────────────────────────────────────

#[tokio::test]
async fn golden_simple_chat_replay_deterministic() {
    let fixtures = load_fixture("simple-chat.json");
    assert_eq!(fixtures.len(), 4, "simple-chat fixture should have 4 events");

    let (_dir, journal) = setup();
    ingest(&journal, &fixtures).await;

    let events = journal
        .read(
            EventQuery::new()
                .session(SessionId::from_string("GOLDEN-SIMPLE-CHAT"))
                .branch(BranchId::from_string("main")),
        )
        .await
        .unwrap();
    assert_eq!(events.len(), 4);

    // First event: SessionCreated
    assert!(
        matches!(&events[0].payload, EventPayload::SessionCreated { name, .. } if name == "simple-chat"),
        "event 0 should be SessionCreated, got {:?}",
        events[0].payload
    );

    // Second event: user message
    assert!(
        matches!(&events[1].payload, EventPayload::Message { role, content, .. } if role == "user" && content == "Hello, agent!"),
        "event 1 should be user Message"
    );

    // Third event: assistant message
    if let EventPayload::Message {
        role,
        content,
        model,
        token_usage,
    } = &events[2].payload
    {
        assert_eq!(role, "assistant");
        assert_eq!(content, "Hello! How can I help you today?");
        assert_eq!(model.as_deref(), Some("gpt-4"));
        let usage = token_usage.as_ref().expect("should have token_usage");
        assert_eq!(usage.prompt_tokens, 10);
        assert_eq!(usage.completion_tokens, 8);
        assert_eq!(usage.total_tokens, 18);
    } else {
        panic!("event 2 should be assistant Message");
    }

    // Fourth event: user message
    assert!(
        matches!(&events[3].payload, EventPayload::Message { role, content, .. } if role == "user" && content == "Thanks, goodbye!"),
        "event 3 should be user Message"
    );
}

#[tokio::test]
async fn golden_simple_chat_head_seq() {
    let fixtures = load_fixture("simple-chat.json");
    let (_dir, journal) = setup();
    ingest(&journal, &fixtures).await;

    let head = journal
        .head_seq(
            &SessionId::from_string("GOLDEN-SIMPLE-CHAT"),
            &BranchId::from_string("main"),
        )
        .await
        .unwrap();
    assert_eq!(head, 4, "head_seq should equal event count after ingest");
}

// ─── tool-round-trip fixtures ───────────────────────────────────────────────

#[tokio::test]
async fn golden_tool_round_trip_replay() {
    let fixtures = load_fixture("tool-round-trip.json");
    assert_eq!(fixtures.len(), 6, "tool-round-trip fixture should have 6 events");

    let (_dir, journal) = setup();
    ingest(&journal, &fixtures).await;

    let events = journal
        .read(
            EventQuery::new()
                .session(SessionId::from_string("GOLDEN-TOOL-RT"))
                .branch(BranchId::from_string("main")),
        )
        .await
        .unwrap();
    assert_eq!(events.len(), 6);

    // ToolCallRequested at index 2
    if let EventPayload::ToolCallRequested {
        call_id,
        tool_name,
        arguments,
        category,
    } = &events[2].payload
    {
        assert_eq!(call_id, "call-001");
        assert_eq!(tool_name, "read_file");
        assert_eq!(arguments["path"], "/etc/hostname");
        assert_eq!(category.as_deref(), Some("fs"));
    } else {
        panic!(
            "event 2 should be ToolCallRequested, got {:?}",
            events[2].payload
        );
    }

    // ToolCallCompleted at index 3
    if let EventPayload::ToolCallCompleted {
        call_id,
        tool_name,
        result,
        duration_ms,
        status,
        ..
    } = &events[3].payload
    {
        assert_eq!(call_id.as_deref(), Some("call-001"));
        assert_eq!(tool_name, "read_file");
        assert_eq!(result["content"], "agent-host");
        assert_eq!(*duration_ms, 12);
        assert_eq!(*status, lago_core::event::SpanStatus::Ok);
    } else {
        panic!(
            "event 3 should be ToolCallCompleted, got {:?}",
            events[3].payload
        );
    }

    // SessionClosed at index 5
    assert!(
        matches!(&events[5].payload, EventPayload::SessionClosed { reason } if reason == "completed"),
        "event 5 should be SessionClosed"
    );
}

#[tokio::test]
