#[tokio::test]
async fn golden_branch_fork_isolation() {
    let fixtures = load_fixture("branch-fork.json");
    assert_eq!(fixtures.len(), 7, "branch-fork fixture should have 7 events");

    let (_dir, journal) = setup();
    ingest(&journal, &fixtures).await;

    // Main branch: events 1-4 and 7 (indices 0,1,2,3,6 — 5 events on main)
    let main_events = journal
        .read(
            EventQuery::new()
                .session(SessionId::from_string("GOLDEN-BRANCH-FORK"))
                .branch(BranchId::from_string("main")),
        )
        .await
        .unwrap();
    assert_eq!(main_events.len(), 5, "main branch should have 5 events");

    // Feature-x branch: events 5,6 (indices 4,5 — 2 events)
    let feature_events = journal
        .read(
            EventQuery::new()
                .session(SessionId::from_string("GOLDEN-BRANCH-FORK"))
                .branch(BranchId::from_string("feature-x")),
        )
        .await
        .unwrap();
    assert_eq!(
        feature_events.len(),
        2,
        "feature-x branch should have 2 events"
    );

    // Verify branch isolation: feature-x events are user and assistant messages
    assert!(matches!(
        &feature_events[0].payload,
        EventPayload::Message { role, content, .. } if role == "user" && content == "Implement feature X"
    ));
    assert!(matches!(
        &feature_events[1].payload,
        EventPayload::Message { role, content, .. } if role == "assistant" && content == "Feature X implemented."
    ));
}

#[tokio::test]
async fn golden_branch_fork_cursor_replay() {
    let fixtures = load_fixture("branch-fork.json");
    let (_dir, journal) = setup();
    ingest(&journal, &fixtures).await;

    // Read main branch from cursor position 3 (should return events 4 and 5)
    let events = journal
        .read(
            EventQuery::new()
                .session(SessionId::from_string("GOLDEN-BRANCH-FORK"))
                .branch(BranchId::from_string("main"))
                .after(3),
        )
        .await
        .unwrap();
    assert_eq!(events.len(), 2, "reading after seq 3 should return 2 events");
    assert_eq!(events[0].seq, 4);
    assert_eq!(events[1].seq, 5);
}

