#[tokio::test]
async fn golden_simple_chat_replay_deterministic() {
    let fixtures = load_fixture("simple-chat.json");
    assert_eq!(
        fixtures.len(),
        4,
        "simple-chat fixture should have 4 events"
    );

    let (_dir, journal) = setup();
    ingest(&journal, &fixtures).await;

    let events = journal
        .read(
            EventQuery::new()
                .session(SessionId::from_string("GOLDEN-SIMPLE-CHAT"))
                .branch(BranchId::from_string("main")),
        )
        .await
        .unwrap();
    assert_eq!(events.len(), 4);

    // First event: SessionCreated
    assert!(
        matches!(&events[0].payload, EventPayload::SessionCreated { name, .. } if name == "simple-chat"),
        "event 0 should be SessionCreated, got {:?}",
        events[0].payload
    );

    // Second event: user message
    assert!(
        matches!(&events[1].payload, EventPayload::Message { role, content, .. } if role == "user" && content == "Hello, agent!"),
        "event 1 should be user Message"
    );

    // Third event: assistant message
    if let EventPayload::Message {
        role,
        content,
        model,
        token_usage,
    } = &events[2].payload
    {
        assert_eq!(role, "assistant");
        assert_eq!(content, "Hello! How can I help you today?");
        assert_eq!(model.as_deref(), Some("gpt-4"));
        let usage = token_usage.as_ref().expect("should have token_usage");
        assert_eq!(usage.prompt_tokens, 10);
        assert_eq!(usage.completion_tokens, 8);
        assert_eq!(usage.total_tokens, 18);
    } else {
        panic!("event 2 should be assistant Message");
    }

    // Fourth event: user message
    assert!(
        matches!(&events[3].payload, EventPayload::Message { role, content, .. } if role == "user" && content == "Thanks, goodbye!"),
        "event 3 should be user Message"
    );
}

